          uColorBottom: { value: new Color("#2a2e44") },
          // slate puddle
          uColorFog: { value: new Color("#354068") },
          // lavender fog
          uSaturation: { value: 1 },
          uBrightness: { value: 1 },
          uCentroid: { value: 0.4 },
          uHarmonicRatio: { value: 0.6 },
          uChromaStrength: { value: 0 },
          uModeWarm: { value: 0 },
          uHueDistance: { value: 0.3 },
